mapper.select:
select user_coupon_id, u.phone_number, c.title, is_used, used_at, received_at, o.order_no, expired_at from user_coupon uc join users u on uc.user_id = u.user_id join orders o on o.order_id = uc.order_id left join coupon c on c.coupon_id = uc.coupon_id
and u.phone_number = #{couponFrom.phoneNumber}
and uc.coupon_id != #{couponFrom.couponId}

select coupon_id
from user_coupon
where user_id = #{user_id};
